import os
path = r'C:\Users\Revexn\Desktop\antigravity\seconde-exp'
skip = {'.venv', '.pytest_cache', '__pycache__', 'node_modules', '.git'}
print('=== TOP-LEVEL DIRS ===')
for item in sorted(os.listdir(path)):
    fp = os.path.join(path, item)
    if os.path.isdir(fp):
        print(f'  [DIR] {item}')
print()
# Search all dirs except skip list, and also skip agent/skills
for root, dirs, files in os.walk(path):
    rel_root = os.path.relpath(root, path)
    # Skip unwanted dirs
    dirs[:] = [d for d in dirs if d not in skip]
    if rel_root.startswith('agent') and 'skills' in rel_root:
        dirs[:] = []
        continue
    if rel_root == 'agent\\skills' or rel_root == 'agent/skills':
        dirs[:] = []
        continue
    for f in files:
        fp = os.path.join(root, f)
        try:
            sz = os.path.getsize(fp)
            if sz > 500000:
                continue
            low = f.lower()
            if any(low.endswith(e) for e in ['.env', '.json', '.txt', '.cfg', '.ini', '.yaml', '.yml', '.toml', '.py', '.bat', '.config']):
                with open(fp, 'r', encoding='utf-8', errors='ignore') as fh:
                    content = fh.read()
                    if any(kw in content.lower() for kw in ['page_id', 'access_token', 'facebook', 'fb_page', 'page_name', 'graph.facebook']):
                        print(f'*** MATCH: {os.path.relpath(fp, path)} ({sz}B) ***')
                        print(content[:5000])
                        print()
        except: pass
print('SEARCH COMPLETE')
